--- /dev/null
+++ b/src/util/sanitize-svg.js
@@ -0,0 +1,42 @@
+/**
+ * Sanitize SVG content to prevent XSS attacks.
+ * Removes dangerous elements and attributes that could execute scripts.
+ */
+
+const DANGEROUS_TAGS = ['script', 'iframe', 'object', 'embed', 'form', 'meta', 'link', 'base'];
+
+/**
+ * Sanitize an SVG string by removing dangerous content.
+ * @param {string} svgString - The SVG string to sanitize.
+ * @returns {string} - Sanitized SVG string.
+ */
+const sanitizeSVG = function (svgString) {
+    if (typeof svgString !== 'string') {
+        return svgString;
+    }
+    
+    let result = svgString;
+    
+    // Remove script tags and their content
+    result = result.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '');
+    
+    // Remove other dangerous tags
+    for (const tag of DANGEROUS_TAGS) {
+        const openCloseRegex = new RegExp(`<${tag}\\b[^>]*>.*?</${tag}>`, 'gis');
+        result = result.replace(openCloseRegex, '');
+        const selfCloseRegex = new RegExp(`<${tag}\\b[^>]*/?>`, 'gi');
+        result = result.replace(selfCloseRegex, '');
+    }
+    
+    // Remove event handler attributes (onclick, onload, onerror, etc.)
+    result = result.replace(/\s+on\w+\s*=\s*("[^"]*"|'[^']*'|[^\s>]*)/gi, '');
+    
+    // Remove javascript: URLs in href, src, and xlink:href attributes
+    result = result.replace(/((?:xlink:)?href|src)\s*=\s*("[^"]*javascript:[^"]*"|'[^']*javascript:[^']*')/gi, '');
+    
+    return result;
+};
+
+module.exports = sanitizeSVG;

