+package org.apache.streampipes.commons.networking;
+
+import java.net.InetAddress;
+import java.net.URL;
+import java.util.Set;
+
+/**
+ * Utility class for validating URLs to prevent SSRF attacks.
+ */
+public class UrlValidator {
+
+    private static final Set<String> ALLOWED_SCHEMES = Set.of("http", "https");
+
+    private UrlValidator() {
+        // Utility class - no instantiation
+    }
+
+    /**
+     * Validates that a URL is safe to use for external HTTP requests.
+     * Prevents SSRF by blocking internal/private IP addresses and non-HTTP schemes.
+     *
+     * @param urlString the URL string to validate
+     * @return true if the URL is valid and safe, false otherwise
+     */
+    public static boolean isValidExternalUrl(String urlString) {
+        if (urlString == null || urlString.isBlank()) {
+            return false;
+        }
+
+        try {
+            URL url = new URL(urlString);
+
+            // Only allow http and https schemes
+            String protocol = url.getProtocol().toLowerCase();
+            if (!ALLOWED_SCHEMES.contains(protocol)) {
+                return false;
+            }
+
+            // Resolve host and check for internal/private addresses
+            String host = url.getHost();
+            if (host == null || host.isBlank()) {
+                return false;
+            }
+
+            InetAddress address = InetAddress.getByName(host);
+            
+            // Block loopback, link-local, site-local, and any local addresses
+            if (address.isLoopbackAddress() 
+                || address.isLinkLocalAddress()
+                || address.isSiteLocalAddress() 
+                || address.isAnyLocalAddress()) {
+                return false;
+            }
+
+            return true;
+        } catch (Exception e) {
+            return false;
+        }
+    }
+}
