+import type { IncomingMessage } from 'http'
+
+/**
+ * Validates request headers to prevent HTTP request smuggling.
+ * 
+ * This addresses CVE-2024-34350 by ensuring consistent interpretation
+ * of request boundaries between Next.js and backend servers.
+ */
+export function validateRequestHeaders(
+  req: IncomingMessage
+): string | null {
+  const contentLength = req.headers['content-length']
+  const transferEncoding = req.headers['transfer-encoding']
+
+  // Reject requests with both Content-Length and Transfer-Encoding
+  // as they can be interpreted inconsistently (CWE-444)
+  if (contentLength && transferEncoding) {
+    return 'Bad Request: Cannot have both Content-Length and Transfer-Encoding headers'
+  }
+
+  // Validate Content-Length is a valid non-negative integer
+  if (contentLength !== undefined) {
+    const length = parseInt(contentLength, 10)
+    if (
+      isNaN(length) ||
+      length < 0 ||
+      !/^\d+$/.test(contentLength as string)
+    ) {
+      return 'Bad Request: Invalid Content-Length header'
+    }
+  }
+
+  // Validate Transfer-Encoding does not contain unexpected values
+  if (transferEncoding) {
+    const encodings = (transferEncoding as string).toLowerCase().split(',')
+    for (const encoding of encodings) {
+      const trimmed = encoding.trim()
+      if (trimmed !== 'chunked' && trimmed !== '') {
+        return 'Bad Request: Invalid Transfer-Encoding value'
+      }
+    }
+  }
+
+  return null
+}

